<span class="line"><span style="color:#F97583;">type</span><span style="color:#E1E4E8;"> </span><span style="color:#B392F0;">MyMap</span><span style="color:#E1E4E8;">[KEY </span><span style="color:#F97583;">int</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">|</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">string</span><span style="color:#E1E4E8;">, VALUE </span><span style="color:#F97583;">float32</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">|</span><span style="color:#E1E4E8;"> </span><span style="color:#F97583;">float64</span><span style="color:#E1E4E8;">] </span><span style="color:#F97583;">map</span><span style="color:#E1E4E8;">[KEY]VALUE  </span></span>
