<span class="line"><span style="color:#F97583;">var</span><span style="color:#E1E4E8;"> s2 Slice[</span><span style="color:#F97583;">map</span><span style="color:#E1E4E8;">[</span><span style="color:#F97583;">string</span><span style="color:#E1E4E8;">]</span><span style="color:#F97583;">string</span><span style="color:#E1E4E8;">]  </span><span style="color:#6A737D;">// 正确</span></span>
